var BLOG_FILTER='all';var BLOG_EDITING=null;function _blEscape(s){return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');}
if(typeof escapeHtml==='undefined'){window.escapeHtml=_blEscape;}
function setBlogFilter(btn,name){document.querySelectorAll('.blog-filter').forEach(function(b){b.classList.remove('active');});if(btn)btn.classList.add('active');BLOG_FILTER=name;loadBlogSection();}
async function loadBlogSection(){var list=document.getElementById('blogList');if(!list)return;list.innerHTML='<div style="text-align:center;color:#444;padding:40px">Loading…</div>';try{var token=getToken();var res=await fetch(ATP_API+'/blog?drafts=1&limit=200',{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var posts=(data&&data.posts)||[];if(BLOG_FILTER==='published')posts=posts.filter(function(p){return p.is_published;});if(BLOG_FILTER==='draft')posts=posts.filter(function(p){return!p.is_published;});if(!posts.length){list.innerHTML='<div style="text-align:center;color:#555;padding:40px;background:#0d0d0d;border:1px dashed #1a1a1a;border-radius:12px">'+'<div style="font-size:36px;margin-bottom:10px;opacity:.4">📝</div>'+'<div style="font-size:14px;color:#aaa">No posts yet — click <strong style="color:#7AC231">+ New post</strong> to write the first one.</div>'+'</div>';return;}
list.innerHTML=posts.map(function(p){var cover=p.cover_image_url?'<img src="'+escapeHtml(p.cover_image_url)+'" alt="">':'<div style="width:100%;height:100%;background:linear-gradient(135deg,#0d1a0a,#1a3e0a);display:flex;align-items:center;justify-content:center;font-size:24px;opacity:.5">📝</div>';var when=p.published_at?new Date(p.published_at).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'}):new Date(p.created_at).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'});var statusLabel=p.is_published?'Published':'Draft';var statusClass=p.is_published?'published':'draft';return'<div class="blog-row" onclick="openBlogEditor(\''+escapeHtml(p.id)+'\')">'+'<div class="blog-row-cover">'+cover+'</div>'+'<div>'+'<div class="blog-row-title">'+escapeHtml(p.title)+'</div>'+'<div class="blog-row-meta">'+'<strong>/blog/'+escapeHtml(p.slug)+'</strong> · '+
escapeHtml(when)+
(p.category?' · '+escapeHtml(p.category):'')+' · '+(p.view_count||0)+' views'+'</div>'+'</div>'+'<div class="blog-row-status '+statusClass+'">'+statusLabel+'</div>'+'</div>';}).join('');}catch(e){list.innerHTML='<div style="text-align:center;color:#f87171;padding:40px">Couldn\'t load posts — '+escapeHtml(e.message||'unknown error')+'</div>';}}
async function openBlogEditor(postId){var modal=document.getElementById('blogModal');var titleH3=document.getElementById('blogEditorTitle');var deleteBtn=document.getElementById('bp-delete');if(!modal)return;modal.classList.add('open');['bp-title','bp-excerpt','bp-body','bp-category','bp-slug','bp-tags'].forEach(function(id){var el=document.getElementById(id);if(el)el.value='';});document.getElementById('bp-published').checked=false;_renderBlogCover('');document.getElementById('bp-msg').textContent='';if(!postId){titleH3.textContent='New post';if(deleteBtn)deleteBtn.style.display='none';BLOG_EDITING=null;renderBlogPreview();return;}
titleH3.textContent='Loading…';try{var token=getToken();var res=await fetch(ATP_API+'/blog?drafts=1&limit=200',{headers:{'Authorization':'Bearer '+token}});var data=await res.json();var post=(data&&data.posts||[]).find(function(p){return p.id===postId;});if(!post){titleH3.textContent='Post not found';return;}
BLOG_EDITING=post;titleH3.textContent='Edit: '+post.title;if(deleteBtn)deleteBtn.style.display='';document.getElementById('bp-title').value=post.title||'';document.getElementById('bp-excerpt').value=post.excerpt||'';document.getElementById('bp-body').value=post.body||'';document.getElementById('bp-category').value=post.category||'';document.getElementById('bp-slug').value=post.slug||'';document.getElementById('bp-tags').value=(post.tags||[]).join(', ');document.getElementById('bp-published').checked=!!post.is_published;_renderBlogCover(post.cover_image_url);renderBlogPreview();}catch(e){titleH3.textContent='Error loading post';}}
function closeBlogEditor(){var modal=document.getElementById('blogModal');if(modal)modal.classList.remove('open');BLOG_EDITING=null;}
function _renderBlogCover(url){var tile=document.getElementById('bp-cover');var empty=document.getElementById('bp-cover-empty');if(!tile)return;Array.from(tile.querySelectorAll('img,video')).forEach(function(n){n.remove();});if(url){var img=document.createElement('img');img.src=url;tile.insertBefore(img,tile.firstChild);if(empty)empty.style.display='none';}else if(empty){empty.style.display='';}
tile.dataset.url=url||'';}
function pickBlogCover(){var input=document.getElementById('bp-cover-file');if(input){input.value='';input.click();}}
async function handleBlogCover(ev){var f=ev.target.files&&ev.target.files[0];if(!f)return;if(f.size>10*1024*1024){showToast('File too large (max 10MB).','danger');return;}
var tile=document.getElementById('bp-cover');if(tile)tile.classList.add('busy');var reader=new FileReader();reader.onload=async function(){try{var token=getToken();var res=await fetch(ATP_API+'/blog/upload',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({data_url:reader.result,filename:f.name,kind:'image'})});var d=await res.json();if(tile)tile.classList.remove('busy');if(!d||!d.success){showToast((d&&d.error)||'Upload failed','danger');return;}
_renderBlogCover(d.url);}catch(e){if(tile)tile.classList.remove('busy');showToast('Upload failed','danger');}};reader.readAsDataURL(f);}
async function saveBlogPost(){var msg=document.getElementById('bp-msg');msg.textContent='Saving…';msg.style.color='#888';var get=function(id){var el=document.getElementById(id);return el?el.value.trim():'';};var coverUrl=(document.getElementById('bp-cover')||{}).dataset&&document.getElementById('bp-cover').dataset.url||null;var tagsRaw=get('bp-tags');var tags=tagsRaw?tagsRaw.split(',').map(function(s){return s.trim();}).filter(Boolean):[];var payload={title:get('bp-title'),excerpt:get('bp-excerpt')||null,cover_image_url:coverUrl,body:get('bp-body')||null,category:get('bp-category')||null,slug:get('bp-slug')||null,tags:tags,is_published:!!document.getElementById('bp-published').checked,};if(!payload.title||payload.title.length<3){msg.textContent='Title is required (3+ chars).';msg.style.color='#fca5a5';return;}
try{var token=getToken();var url=BLOG_EDITING?ATP_API+'/blog/'+encodeURIComponent(BLOG_EDITING.id):ATP_API+'/blog';var method=BLOG_EDITING?'PUT':'POST';var res=await fetch(url,{method:method,headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify(payload)});var d=await res.json();if(!res.ok){msg.textContent=(d&&d.error)||'Save failed.';msg.style.color='#fca5a5';return;}
showToast(BLOG_EDITING?'✓ Post updated':'✓ Post created','success');closeBlogEditor();loadBlogSection();}catch(e){msg.textContent='Network error.';msg.style.color='#fca5a5';}}
function _blRenderBody(raw){if(!raw)return'';var trimmed=String(raw).trim();var hasHtml=/<\/?(p|div|h[1-6]|ul|ol|li|img|video|iframe|figure|blockquote|pre|code|strong|em|a|br|hr|span)\b/i.test(trimmed);if(hasHtml)return trimmed;var esc=function(s){return _blEscape(s);};function inline(s){return esc(s).replace(/!\[([^\]]*)\]\(([^)\s]+)\)/g,'<img src="$2" alt="$1">').replace(/\[([^\]]+)\]\(([^)\s]+)\)/g,'<a href="$2" target="_blank" rel="noopener">$1</a>').replace(/\*\*([^*]+)\*\*/g,'<strong>$1</strong>').replace(/(^|[^*])\*([^*\n]+)\*/g,'$1<em>$2</em>');}
return trimmed.split(/\n\s*\n/).map(function(block){var t=block.trim();if(!t)return'';if(/^###\s+/.test(t))return'<h3>'+inline(t.replace(/^###\s+/,''))+'</h3>';if(/^##\s+/.test(t))return'<h2>'+inline(t.replace(/^##\s+/,''))+'</h2>';if(/^>\s+/.test(t))return'<blockquote>'+inline(t.replace(/^>\s+/,'').replace(/\n>\s+/g,' '))+'</blockquote>';if(/^---+$/.test(t))return'<hr>';if(/^[-*]\s+/.test(t)){var items=t.split(/\n[-*]\s+/).map(function(l,i){return i===0?l.replace(/^[-*]\s+/,''):l;});return'<ul>'+items.map(function(li){return'<li>'+inline(li)+'</li>';}).join('')+'</ul>';}
return'<p>'+inline(t).replace(/\n/g,'<br>')+'</p>';}).join('\n');}
var _blPreviewTimer=null;function renderBlogPreview(){if(_blPreviewTimer)clearTimeout(_blPreviewTimer);_blPreviewTimer=setTimeout(function(){var ta=document.getElementById('bp-body');var pane=document.getElementById('bp-preview');if(!ta||!pane)return;var raw=ta.value||'';if(!raw.trim()){pane.classList.add('empty');pane.innerHTML="Start writing — your post will render here as it'll appear on the public page.";return;}
pane.classList.remove('empty');pane.innerHTML=_blRenderBody(raw);},120);}
function insertBlogMarkdown(prefix,suffix,mode){var ta=document.getElementById('bp-body');if(!ta)return;ta.focus();var start=ta.selectionStart;var end=ta.selectionEnd;var v=ta.value;var sel=v.slice(start,end);var newSel;if(mode==='wrap'){if(sel){ta.value=v.slice(0,start)+prefix+sel+suffix+v.slice(end);newSel=[start+prefix.length,end+prefix.length];}else{var placeholder=prefix==='**'?'bold text':prefix==='*'?'italic text':'text';ta.value=v.slice(0,start)+prefix+placeholder+suffix+v.slice(end);newSel=[start+prefix.length,start+prefix.length+placeholder.length];}}else{var lineStart=v.lastIndexOf('\n',start-1)+1;ta.value=v.slice(0,lineStart)+prefix+v.slice(lineStart);newSel=[start+prefix.length,end+prefix.length];}
ta.setSelectionRange(newSel[0],newSel[1]);renderBlogPreview();}
function promptBlogLink(){var url=prompt('Link URL (https://…):');if(!url)return;var ta=document.getElementById('bp-body');var sel=ta.value.slice(ta.selectionStart,ta.selectionEnd);var label=sel||prompt('Link text:','')||url;var insert='['+label+']('+url+')';var start=ta.selectionStart;ta.value=ta.value.slice(0,start)+insert+ta.value.slice(ta.selectionEnd);ta.focus();ta.setSelectionRange(start+insert.length,start+insert.length);renderBlogPreview();}
function pickBlogInlineImage(){var input=document.getElementById('bp-inline-file');if(input){input.value='';input.click();}}
async function handleBlogInlineImage(ev){var f=ev.target.files&&ev.target.files[0];if(!f)return;await _uploadAndInsertInline(f);}
async function _uploadAndInsertInline(file){if(file.size>10*1024*1024){showToast('File too large (max 10MB).','danger');return;}
var ta=document.getElementById('bp-body');if(!ta)return;var start=ta.selectionStart;var end=ta.selectionEnd;var placeholder='\n\n![uploading…](uploading)\n\n';ta.value=ta.value.slice(0,start)+placeholder+ta.value.slice(end);ta.setSelectionRange(start,start+placeholder.length);ta.focus();showToast('Uploading image…','info');try{var token=getToken();var dataUrl=await new Promise(function(resolve,reject){var reader=new FileReader();reader.onload=function(){resolve(reader.result);};reader.onerror=function(){reject(new Error('read failed'));};reader.readAsDataURL(file);});var res=await fetch(ATP_API+'/blog/upload',{method:'POST',headers:{'Content-Type':'application/json','Authorization':'Bearer '+token},body:JSON.stringify({data_url:dataUrl,filename:file.name,kind:'image'})});var d=await res.json();if(!d||!d.success){ta.value=ta.value.replace(placeholder,'');showToast((d&&d.error)||'Upload failed','danger');return;}
var alt=(file.name||'image').replace(/\.[^.]+$/,'').replace(/[_-]+/g,' ').trim();var markdown='\n\n!['+alt+']('+d.url+')\n\n';ta.value=ta.value.replace(placeholder,markdown);var caret=ta.value.indexOf(markdown)+markdown.length;ta.setSelectionRange(caret,caret);renderBlogPreview();showToast('✓ Image inserted','success');}catch(e){ta.value=ta.value.replace(placeholder,'');showToast('Upload failed','danger');}}
(function _wireBlogBodyDragDrop(){var attach=function(){var ta=document.getElementById('bp-body');if(!ta||ta._dragWired)return;ta._dragWired=true;ta.addEventListener('dragover',function(ev){if(ev.dataTransfer&&ev.dataTransfer.types&&ev.dataTransfer.types.indexOf('Files')!==-1){ev.preventDefault();ta.style.borderColor='rgba(122,194,49,.6)';ta.style.background='#0a0f08';}});ta.addEventListener('dragleave',function(){ta.style.borderColor='';ta.style.background='';});ta.addEventListener('drop',function(ev){if(!ev.dataTransfer||!ev.dataTransfer.files||!ev.dataTransfer.files.length)return;ev.preventDefault();ta.style.borderColor='';ta.style.background='';var f=ev.dataTransfer.files[0];if(!/^image\//.test(f.type)){showToast('Only image files can be dropped here.','danger');return;}
_uploadAndInsertInline(f);});ta.addEventListener('keydown',function(ev){if(!(ev.metaKey||ev.ctrlKey))return;if(ev.key==='b'||ev.key==='B'){ev.preventDefault();insertBlogMarkdown('**','**','wrap');}
else if(ev.key==='i'||ev.key==='I'){ev.preventDefault();insertBlogMarkdown('*','*','wrap');}});};if(document.readyState!=='loading')attach();else document.addEventListener('DOMContentLoaded',attach);})();async function deleteBlogPost(){if(!BLOG_EDITING)return;if(!confirm('Delete "'+BLOG_EDITING.title+'" — this cannot be undone.'))return;try{var token=getToken();var res=await fetch(ATP_API+'/blog/'+encodeURIComponent(BLOG_EDITING.id),{method:'DELETE',headers:{'Authorization':'Bearer '+token}});var d=await res.json();if(!res.ok){showToast((d&&d.error)||'Delete failed','danger');return;}
showToast('✓ Post deleted','success');closeBlogEditor();loadBlogSection();}catch(e){showToast('Network error','danger');}}